import java.util.Scanner;

public class BufferOverflowExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.next();

        // Creating a fixed size byte array
        byte[] buffer = new byte[10];

        // Copying the user input into the buffer without proper length checking
        System.arraycopy(input.getBytes(), 0, buffer, 0, input.length());

        System.out.println("Buffer overflow example completed.");
    }
}

